	public struct PooledObject<T>(T value, IObjectPool<T> pool) : IDisposable where T : class
	{
		private readonly T m_ToReturn = value;

		private readonly IObjectPool<T> m_Pool = pool;

		void IDisposable.Dispose()
		{
			m_Pool.Release(m_ToReturn);
		}
	}
	internal static class PoolManager
	{
		private static readonly List<WeakReference<IPool>> s_WeakPoolReferences = new List<WeakReference<IPool>>();

		public static void Reset()
		{
			for (int num = s_WeakPoolReferences.Count - 1; num >= 0; num--)
			{
				if (s_WeakPoolReferences[num].TryGetTarget(out var target))
				{
					target.Clear();
				}
				else
				{
					s_WeakPoolReferences.RemoveAt(num);
				}
			}
		}

		public static void Register(IPool pool)
		{
			s_WeakPoolReferences.Add(new WeakReference<IPool>(pool));
		}
	}
	public static class UnsafeGenericPool<T> where T : class, new()
	{
		internal static readonly ObjectPool<T> s_Pool = new ObjectPool<T>(() => new T(), null, null, null, collectionCheck: false);

		public static T Get()
		{
			return s_Pool.Get();
		}

		public static PooledObject<T> Get(out T value)
		{
			return s_Pool.Get(out value);
		}

		public static void Release(T toRelease)
		{
			s_Pool.Release(toRelease);
