		public int AddInstancesIndirect(in RayTracingMeshInstanceConfig config, GraphicsBuffer instanceMatrices, int maxInstanceCount, GraphicsBuffer argsBuffer, [UnityEngine.Internal.DefaultValue("0")] uint argsOffset = 0u, uint id = uint.MaxValue)
